<script>
/**
 * 🎛️ LeftPanel.vue - 左側控制面板組件
 * 
 * 功能說明：
 * 1. 📥 提供台南市數據載入功能
 * 2. 📁 提供拖曳上傳檔案功能
 * 3. 🔬 提供空間分析啟動控制
 * 4. 🗺️ 提供圖層顯示控制
 * 5. 🔍 提供數據篩選功能
 * 6. 📊 顯示系統狀態資訊
 */
import { ref, toRaw } from 'vue'
import ActionButton from '../components/common/ActionButton.vue'

export default {
  name: 'LeftPanel',
  components: {
    ActionButton
  },
  /**
   * 🔧 組件屬性定義 (Component Props)
   * 接收來自父組件的數據和狀態
   */
  props: {
    isLoadingData: { type: Boolean, default: false, required: true },
    canStartAnalysis: { type: Boolean, default: false, required: true },
    showTainanLayer: { type: Boolean, default: false, required: true },
    selectedFilter: { type: String, default: '', required: true },
    leftPanelWidth: { type: Number, default: 20, required: true },
    dataSummary: { type: Object, default: null },
    analysisList: { type: Array, default: () => [], required: true },
    zoomLevel: { type: Number, default: 10, required: true },
    activeMarkers: { type: Number, default: 0, required: true },
    mergedTableData: { type: Array, default: () => [] }
  },
  
  /**
   * 📡 組件事件定義 (Component Events)
   * 向父組件發送的事件
   */
  emits: [
    'load-all-data',
    'start-analysis',
    'update:showTainanLayer',
    'update:selectedFilter',
    'files-uploaded',
    'update:zoomLevel',
    'update:activeMarkers',
    'fit-map-to-data',
    'clear-tainan-data',
    'switch-to-dashboard'
  ],

  /**
   * 📊 組件數據設定 (Component Data)
   */
  setup(props, { emit }) {
    // 拖曳上傳相關狀態
    const isDragOver = ref(false)
    const uploadedFiles = ref([])
    const fileInput = ref(null)
    
    // 分析方法選擇
    const analysisMethods = ref([
      { text: '空間自相關 (Moran\'s I)', value: 'morans_i' },
      { text: '點模式分析 (Nearest Neighbor)', value: 'point_pattern' },
      { text: '核密度分析 (Kernel Density)', value: 'kernel_density' },
      { text: '熱點分析 (Getis-Ord Gi*)', value: 'hotspot_analysis' },
      { text: '地理加權回歸 (GWR)', value: 'gwr' }
    ]);
    const selectedAnalysisMethod = ref( (analysisMethods.value && analysisMethods.value.length > 0) ? analysisMethods.value[0] : null );

    // Added: Console logging for debugging
    console.log('[LeftPanel setup] analysisMethods:', JSON.stringify(toRaw(analysisMethods.value)));
    console.log('[LeftPanel setup] selectedAnalysisMethod:', JSON.stringify(toRaw(selectedAnalysisMethod.value)));

    /**
     * 選擇分析方法
     * @param {Object} method - 選擇的分析方法
     */
    const selectAnalysisMethod = (method) => {
      selectedAnalysisMethod.value = method;
      console.log('[LeftPanel] Selected analysis method:', method);
    };

    /**
     * 觸發檔案選擇
     */
    const triggerFileInput = () => {
      fileInput.value.click();
    };

    /**
     * 處理檔案選擇
     * @param {Event} event - 檔案選擇事件
     */
    const handleFileSelect = (event) => {
      const files = Array.from(event.target.files);
      handleFiles(files);
    };

    /**
     * 處理拖曳進入
     * @param {Event} event - 拖曳事件
     */
    const handleDragEnter = (event) => {
      event.preventDefault();
      isDragOver.value = true;
    };

    /**
     * 處理拖曳離開
     */
    const handleDragLeave = () => {
      isDragOver.value = false;
    };

    /**
     * 處理拖曳懸停
     * @param {Event} event - 拖曳事件
     */
    const handleDragOver = (event) => {
      event.preventDefault();
    };

    /**
     * 處理檔案拖放
     * @param {Event} event - 拖放事件
     */
    const handleDrop = (event) => {
      event.preventDefault();
      isDragOver.value = false;
      const files = Array.from(event.dataTransfer.files);
      handleFiles(files);
    };

    /**
     * 處理檔案上傳
     * @param {Array} files - 檔案列表
     */
    const handleFiles = (files) => {
      const newFiles = files.map(file => ({
        id: Date.now() + Math.random(),
        name: file.name,
        size: file.size,
        type: file.type
      }));
      
      uploadedFiles.value = [...uploadedFiles.value, ...newFiles];
      emit('files-uploaded', newFiles);
    };

    /**
     * 移除檔案
     * @param {string} fileId - 檔案ID
     */
    const removeFile = (fileId) => {
      uploadedFiles.value = uploadedFiles.value.filter(file => file.id !== fileId);
    };

    /**
     * 格式化檔案大小
     * @param {number} bytes - 檔案大小（位元組）
     * @returns {string} 格式化後的檔案大小
     */
    const formatFileSize = (bytes) => {
      if (bytes === 0) return '0 Bytes';
      const k = 1024;
      const sizes = ['Bytes', 'KB', 'MB', 'GB'];
      const i = Math.floor(Math.log(bytes) / Math.log(k));
      return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
    };

    return {
      isDragOver,
      uploadedFiles,
      fileInput,
      analysisMethods,
      selectedAnalysisMethod,
      selectAnalysisMethod,
      triggerFileInput,
      handleFileSelect,
      handleDragEnter,
      handleDragLeave,
      handleDragOver,
      handleDrop,
      removeFile,
      formatFileSize
    }
  }
}
</script>

<template>
  <!-- 🎛️ 左側控制面板 - 簡化版本，減少卡片使用，節省空間 -->
  <div class="bg-light border-end h-100 d-flex flex-column" style="overflow: hidden;">
    
    <!-- 📋 面板標題區域 (Panel Header Section) -->
    <div class="p-3" style="min-width: 0;">
      <h1 class="my-font-size-xl" style="overflow: hidden; white-space: nowrap; text-overflow: ellipsis;">
        <div class="d-flex flex-column align-items-center justify-content-center m-3">
          <div class="rounded-circle my-bg-color-gray-300 p-4"></div>
          <div class="my-font-size-lg my-letter-spacing-lg mt-3">登革熱空間分析</div>
        </div>
      </h1>
    </div>

    <!-- 🎛️ 主控制區域 (Main Control Area) - 使用緊湊樣式 -->
    <div class="flex-grow-1 overflow-auto p-3" style="min-width: 0;">
      
      <!-- 📥 拖曳上傳區域 (Drag Upload Area) - 去除卡片包裝 -->
      <div class="mb-3">
        <h6 class="text-muted small text-uppercase mb-2">數據上傳</h6>
        <div 
          class="my-drag-upload-area border border-dashed rounded text-center bg-white p-3"
          :class="{ 'border-primary bg-light': isDragOver }"
          @drop="handleDrop"
          @dragover.prevent="handleDragOver"
          @dragenter.prevent="handleDragEnter"
          @dragleave="handleDragLeave"
          @click="triggerFileInput">
          
          <div class="mb-2">
            <i class="fas fa-cloud-upload-alt fa-lg text-muted"></i>
          </div>
          
          <div class="my-font-size-sm mb-1">xlsx檔案上傳</div>
          <div class="my-font-size-xs text-muted">拖曳檔案或點擊此處</div>
          
          <input
            ref="fileInput"
            type="file"
            class="d-none"
            accept=".geojson,.json,.csv,.xlsx,.xls"
            multiple
            @change="handleFileSelect">
        </div>
        
        <div v-if="uploadedFiles.length > 0" class="mt-2">
          <div class="list-group list-group-flush">
            <div v-for="file in uploadedFiles" :key="file.id" 
                 class="list-group-item list-group-item-action p-2 d-flex justify-content-between align-items-center bg-white rounded mb-1 shadow-sm">
              <div class="flex-grow-1 me-2">
                <div class="small fw-medium text-truncate" :title="file.name">{{ file.name }}</div>
                <small class="text-muted">{{ formatFileSize(file.size) }}</small>
              </div>
              <button 
                class="btn btn-outline-danger btn-sm border-0" 
                @click="removeFile(file.id)"
                title="移除檔案">
                <i class="fas fa-times"></i>
              </button>
            </div>
          </div>
        </div>
      </div>

      <!-- 📥 數據載入區域 (Data Loading Section) -->
      <div class="mb-3">
        <h6 class="text-muted small text-uppercase mb-2">數據處理</h6>
        <div class="d-grid">
          <button 
            class="btn btn-success" 
            @click="$emit('load-all-data')" 
            :disabled="isLoadingData">
            <span v-if="isLoadingData">
              <span class="spinner-border spinner-border-sm me-1" role="status"></span>
              載入中...
            </span>
            <span v-else><i class="fas fa-database me-1"></i> 載入預設數據</span>
          </button>
        </div>
      </div>

      <!-- ⚙️ 空間分析方法選擇 (Spatial Analysis Method Selection) -->
      <div class="mb-3">
        <h6 class="text-muted small text-uppercase mb-2">空間分析方法</h6>
        <div class="dropdown">
          <button class="btn btn-outline-secondary dropdown-toggle w-100" type="button" id="spatialAnalysisMethodDropdown" data-bs-toggle="dropdown" aria-expanded="false">
            <span v-if="selectedAnalysisMethod && selectedAnalysisMethod.text">{{ selectedAnalysisMethod.text }}</span>
            <span v-else>選擇分析方法</span>
            <i class="fas fa-chevron-down fa-xs ms-1"></i>
          </button>
          <ul class="dropdown-menu w-100" aria-labelledby="spatialAnalysisMethodDropdown">
            <template v-if="analysisMethods && analysisMethods.length > 0">
              <li v-for="method in analysisMethods" :key="method.value">
                <a class="dropdown-item" href="#" @click.prevent="selectAnalysisMethod(method)">
                  {{ method.text }}
                </a>
              </li>
            </template>
            <template v-else>
              <li class="dropdown-item disabled">分析方法加載中或為空...</li>
            </template>
          </ul>
        </div>
      </div>

      <!-- 🔬 分析控制區域 (Analysis Control Section) -->
      <div class="mb-3">
         <h6 class="text-muted small text-uppercase mb-2">空間分析執行</h6>
        <div class="d-grid">
          <button 
            class="btn btn-primary" 
            @click="$emit('start-analysis', selectedAnalysisMethod ? selectedAnalysisMethod.value : null)" 
            :disabled="!canStartAnalysis">
            開始分析
          </button>
        </div>
      </div>

      <!-- 圖層控制卡片 -->
      <div class="mb-3">
        <h6 class="text-muted small text-uppercase mb-2">圖層控制</h6>
        <div class="d-grid gap-2">
          <ActionButton 
            @click="$emit('clear-tainan-data')"
            :disabled="!mergedTableData || mergedTableData.length === 0"
            variant="outline-warning"
            icon="trash"
            text="清除數據" />
        </div>
      </div>
 
    </div>

  </div>
</template>

