<script>
/**
 * 📊 DashboardView.vue - 數據儀表板組件
 * 
 * 功能說明：
 * 1. 📊 顯示統計數據卡片
 * 2. 📈 提供數據分布柱狀圖
 * 3. 📊 提供區域比例圓餅圖
 * 4. 🎨 使用D3.js進行圖表渲染
 * 5. 📱 響應式設計支援
 */
import { ref, computed, watch, onMounted, nextTick } from 'vue'
import * as d3 from 'd3'
import { formatNumber } from '../utils/utils.js'
import { useDataStore } from '@/stores/dataStore'

export default {
  name: 'DashboardView',
  components: {
  },
  /**
   * 🔧 組件屬性定義 (Component Props)
   */
  props: {
    containerHeight: { type: Number, default: 500, required: true },
    isPanelDragging: { type: Boolean, default: false },
    activeMarkers: { type: Number, default: 0 }
  },
  
  /**
   * 🔧 組件設定函數 (Component Setup)
   */
  setup() {
    const dataStore = useDataStore();
    // 📚 組件引用 (Component References)
    const barChart = ref(null)
    const pieChart = ref(null)

    // 直接從 dataStore 取得 loadedAndMergedTableData
    const loadedAndMergedTableData = computed(() => dataStore.processedData.loadedAndMergedTableData)

    // 分組區間
    const countRanges = [
      { name: '0-10', min: 0, max: 10, color: '#28a745' },
      { name: '11-25', min: 11, max: 25, color: '#ffc107' },
      { name: '26-50', min: 26, max: 50, color: '#fd7e14' },
      { name: '51-100', min: 51, max: 100, color: '#dc3545' },
      { name: '100+', min: 101, max: Infinity, color: '#6f42c1' }
    ]

    // 柱狀圖與圓餅圖共用的分組統計
    const countGroupStats = computed(() => {
      const stats = countRanges.map(r => ({ ...r, value: 0 }))
      if (!loadedAndMergedTableData.value || loadedAndMergedTableData.value.length === 0) return stats
      loadedAndMergedTableData.value.forEach(row => {
        const count = row.count || 0
        const range = stats.find(r => count >= r.min && count <= r.max)
        if (range) range.value++
      })
      return stats
    })

    // 柱狀圖
    const createBarChart = () => {
      if (!barChart.value) return
      const container = barChart.value.parentElement
      if (!container) return
      d3.select(barChart.value).selectAll("*").remove()
      const containerRect = container.getBoundingClientRect()
      const margin = { top: 20, right: 30, bottom: 60, left: 80 }
      const width = Math.max(300, containerRect.width - margin.left - margin.right)
      const height = Math.max(200, containerRect.height - margin.top - margin.bottom)
      const svg = d3.select(barChart.value)
        .append("svg")
        .attr("width", width + margin.left + margin.right)
        .attr("height", height + margin.top + margin.bottom)
        .style("max-width", "100%")
        .style("height", "auto")
      const g = svg.append("g")
        .attr("transform", `translate(${margin.left},${margin.top})`)
      const x = d3.scaleBand()
        .rangeRound([0, width])
        .padding(0.1)
        .domain(countGroupStats.value.map(d => d.name))
      const y = d3.scaleLinear()
        .rangeRound([height, 0])
        .domain([0, d3.max(countGroupStats.value, d => d.value) || 1])
      g.append("g")
        .attr("transform", `translate(0,${height})`)
        .call(d3.axisBottom(x))
        .selectAll("text")
        .style("text-anchor", "end")
        .attr("dx", "-.8em")
        .attr("dy", ".15em")
        .attr("transform", "rotate(-45)")
      g.append("g")
        .call(d3.axisLeft(y))
      g.append("text")
        .attr("transform", "rotate(-90)")
        .attr("y", 0 - margin.left)
        .attr("x", 0 - (height / 2))
        .attr("dy", "1em")
        .style("text-anchor", "middle")
        .style("font-size", "12px")
        .text("區域數量")
      g.selectAll(".bar")
        .data(countGroupStats.value)
        .enter().append("rect")
        .attr("class", "bar")
        .attr("x", d => x(d.name))
        .attr("y", d => y(d.value))
        .attr("width", x.bandwidth())
        .attr("height", d => height - y(d.value))
        .attr("fill", d => d.color)
        .style("cursor", "pointer")
        .append("title")
        .text(d => `${d.name}: ${d.value} 區域`)
      g.selectAll(".label")
        .data(countGroupStats.value)
        .enter().append("text")
        .attr("class", "label")
        .attr("x", d => x(d.name) + x.bandwidth() / 2)
        .attr("y", d => y(d.value) - 5)
        .attr("text-anchor", "middle")
        .style("font-size", "12px")
        .style("font-weight", "bold")
        .text(d => d.value)
    }

    // 圓餅圖
    const createPieChart = () => {
      if (!pieChart.value) return
      const container = pieChart.value.parentElement
      if (!container) return
      d3.select(pieChart.value).selectAll("*").remove()
      const containerRect = container.getBoundingClientRect()
      const width = Math.max(300, containerRect.width)
      const height = Math.max(220, containerRect.height)
      const radius = Math.min(width, height) / 2 - 10
      const svg = d3.select(pieChart.value)
        .append("svg")
        .attr("width", width)
        .attr("height", height)
        .style("max-width", "100%")
        .style("height", "auto")
      const g = svg.append("g")
        .attr("transform", `translate(${width / 2},${height / 2})`)
      const pie = d3.pie().value(d => d.value)
      const data_ready = pie(countGroupStats.value)
      g.selectAll('path')
        .data(data_ready)
        .enter()
        .append('path')
        .attr('d', d3.arc()
          .innerRadius(0)
          .outerRadius(radius)
        )
        .attr('fill', d => d.data.color)
        .attr('stroke', '#fff')
        .style('stroke-width', '2px')
        .append('title')
        .text(d => `${d.data.name}: ${d.data.value} 區域`)
      g.selectAll('text')
        .data(data_ready)
        .enter()
        .append('text')
        .text(d => d.data.value > 0 ? `${d.data.name} (${d.data.value})` : '')
        .attr('transform', d => {
          const _d = d3.arc().innerRadius(0).outerRadius(radius).centroid(d)
          return `translate(${_d[0]},${_d[1]})`
        })
        .style('text-anchor', 'middle')
        .style('font-size', '13px')
        .style('font-weight', 'bold')
    }

    // 監聽資料變動時重繪所有圖表
    watch(loadedAndMergedTableData, () => {
      nextTick(() => {
        createBarChart()
        createPieChart()
      })
    }, { deep: true })

    /**
     * 👀 監聽面板拖曳狀態以調整圖表的指針事件
     */
    watch(() => dataStore.processedData.isPanelDragging, (dragging) => {
      nextTick(() => {
        if (barChart.value) {
          barChart.value.style.pointerEvents = dragging ? 'none' : 'auto';
          console.log(`DashboardView: Bar chart pointer-events set to ${barChart.value.style.pointerEvents}`);
        }
        if (pieChart.value) {
          pieChart.value.style.pointerEvents = dragging ? 'none' : 'auto';
          console.log(`DashboardView: Pie chart pointer-events set to ${pieChart.value.style.pointerEvents}`);
        }
      });
    }, { immediate: true });

    /**
     * 🚀 組件掛載 (Component Mounted)
     */
    onMounted(() => {
      nextTick(() => {
        createBarChart()
        createPieChart()
      })
    })

    const excelData = computed(() => dataStore.rawData.excelData)
    // 例如：畫一個人口數量的直方圖
    const populationHistogram = computed(() => {
      if (!excelData.value || excelData.value.length === 0) return []
      // 假設 excelData 每筆有 population 欄位
      return excelData.value.map(row => ({
        name: row.name,
        population: row.population || 0
      }))
    })

    // 📤 返回數據和方法 (Return Data and Methods)
    return {
      barChart,
      pieChart,
      countGroupStats,
      formatNumber,
      dataStore,
      excelData,
      populationHistogram,
      loadedAndMergedTableData
    }
  }
}
</script>

<template>
  <div class="dashboard-container">
    <!-- 🐞 Debug 區塊 -->
    <div class="debug-block">
      <strong>Debug: loadedAndMergedTableData</strong>
      <pre>{{ JSON.stringify(loadedAndMergedTableData, null, 2) }}</pre>
      <strong>Debug: dataSummary</strong>
      <pre>{{ JSON.stringify(dataStore.processedData.dataSummary, null, 2) }}</pre>
    </div>
    <!-- 📊 統計卡片區 -->
    <div class="stats-cards-row">
      <div class="stat-card">
        <div class="stat-title">總數據點</div>
        <div class="stat-value">{{ formatNumber(dataStore.processedData.dataSummary?.totalCount || 0) }}</div>
      </div>
      <div class="stat-card">
        <div class="stat-title">最高值</div>
        <div class="stat-value">{{ formatNumber(dataStore.processedData.dataSummary?.maxCount || 0) }}</div>
      </div>
      <div class="stat-card">
        <div class="stat-title">平均值</div>
        <div class="stat-value">{{ dataStore.processedData.dataSummary?.averageCount?.toFixed(1) || '0.0' }}</div>
      </div>
      <div class="stat-card">
        <div class="stat-title">有數據區域</div>
        <div class="stat-value">{{ formatNumber(dataStore.processedData.dataSummary?.dataRegionsCount || 0) }}</div>
      </div>
    </div>
    <hr class="dashboard-divider" />
    <!-- 📈 只保留兩個圖表 -->
    <div class="charts-row">
      <div class="chart-card">
        <div class="chart-title">Count 分組柱狀圖</div>
        <div ref="barChart" class="chart-area"></div>
      </div>
      <div class="chart-card">
        <div class="chart-title">Count 分組圓餅圖</div>
        <div ref="pieChart" class="chart-area"></div>
      </div>
    </div>
  </div>
</template>

