/**
 * 🗺️ router/index.js - 路由配置文件
 * 
 * 功能說明：
 * 1. 📱 定義應用程式路由結構
 * 2. 🔄 管理頁面導航
 * 3. 🎯 配置路由元信息
 * 4. 🛡️ 處理路由守衛
 */

// 🧩 引入必要的依賴
import { createRouter, createWebHistory } from 'vue-router'  // Vue Router

// 📦 引入視圖組件
import HomeView from '../views/HomeView.vue'                 // 首頁視圖
import DataView from '../views/DataView.vue'                 // 數據視圖
import ContentView from '../views/ContentView.vue'             // 內容視圖
import DesignView from '../views/DesignView.vue'               // 設計視圖

// 📦 定義路由配置
const router = createRouter({
  // 📦 使用 HTML5 History 模式
  history: createWebHistory(import.meta.env.BASE_URL),
  
  // 📦 路由配置
  routes: [
    {
      path: '/',                    // 📍 根路徑
      name: 'home',                 // 📌 路由名稱
      component: HomeView,          // 📦 組件
      meta: {
        title: '首頁',              // 📄 頁面標題
        requiresAuth: false         // 🔒 是否需要認證
      }
    },
    {
      path: '/data',                // 📍 數據頁面路徑
      name: 'data',                 // 📌 路由名稱
      component: DataView,          // 📦 組件
      meta: {
        title: '數據管理',          // 📄 頁面標題
        requiresAuth: false         // 🔒 是否需要認證
      }
    },
    {
      path: '/content',             // 📍 內容頁面路徑
      name: 'content',              // 📌 路由名稱
      component: ContentView,       // 📦 組件
      meta: {
        title: '內容管理',          // 📄 頁面標題
        requiresAuth: false         // 🔒 是否需要認證
      }
    },
    {
      path: '/design',              // 📍 設計頁面路徑
      name: 'design',               // 📌 路由名稱
      component: DesignView,        // 📦 組件
      meta: {
        title: '設計系統',          // 📄 頁面標題
        requiresAuth: false         // 🔒 是否需要認證
      }
    }
  ]
})

// 🔒 全局前置守衛
router.beforeEach((to, from, next) => {
  // 設置頁面標題
  document.title = to.meta.title ? `${to.meta.title} - 空間分析視覺化平台` : '空間分析視覺化平台'
  
  // 檢查是否需要認證
  if (to.meta.requiresAuth) {
    // 這裡可以添加認證邏輯
    next()
  } else {
    next()
  }
})

// 🔄 全局後置守衛
router.afterEach((to, from) => {
  // 路由切換後的操作
  console.log(`🔄 路由已切換: ${from.path} -> ${to.path}`)
})

export default router 