/**
 * 📦 mapStore.js - 地圖管理 Store
 * 
 * 功能說明：
 * 1. 🎨 管理地圖面板尺寸和響應式佈局
 * 2. 🗺️ 管理地圖圖層和視覺化狀態
 * 3. 📊 管理地圖相關的統計數據
 * 4. 🔄 提供座標轉換功能
 */

// 🧩 引入必要的依賴
import { defineStore } from 'pinia'                    // Pinia 狀態管理
import { ref, computed } from 'vue'                    // Vue 響應式 API
import { transformTWD97ToWGS84, transformGeoJSONCoordinates } from '../utils/spatialAnalysis.js'  // 空間分析工具

// 📦 定義地圖管理 store
export const useMapStore = defineStore('map', () => {
  // ==================== 面板尺寸狀態 ====================
  const leftPanelWidth = ref(300)      // 左側面板寬度
  const rightPanelWidth = ref(300)     // 右側面板寬度
  const bottomPanelHeight = ref(250)   // 底部面板高度
  const windowWidth = ref(window.innerWidth)    // 視窗寬度
  const windowHeight = ref(window.innerHeight)  // 視窗高度

  // ==================== 地圖和控制項狀態 ====================
  const showLayer1 = ref(true)         // 圖層1顯示狀態
  const showLayer2 = ref(false)        // 圖層2顯示狀態
  const selectedFilter = ref('')       // 當前選擇的過濾器
  const timeRange = ref(50)            // 時間範圍
  const zoomLevel = ref(10)            // 地圖縮放級別
  const currentCoords = ref({ lat: 25.0330, lng: 121.5654 })  // 當前地圖中心點
  const totalCount = ref(1250000)      // 總數據點數
  const selectedCount = ref(0)         // 選中的數據點數
  const chartType = ref('bar')         // 圖表類型

  // ==================== 地圖圖層狀態 ====================
  const mapLayers = ref({
    geojsonLayer: null,    // GeoJSON 圖層
    pointLayer: null,      // 點圖層
    heatmapLayer: null,    // 熱力圖圖層
    clusterLayer: null,    // 聚合圖層
    bufferLayer: null      // 緩衝區圖層
  })

  // ==================== 座標轉換狀態 ====================
  const coordinateSystem = ref('WGS84')  // 當前座標系統（WGS84 或 TWD97）
  const transformedData = ref(null)      // 轉換後的數據

  // ==================== Bootstrap RWD 斷點 ====================
  const breakpoints = {
    xs: 0,      // 超小螢幕
    sm: 576,    // 小螢幕
    md: 768,    // 中等螢幕
    lg: 992,    // 大螢幕
    xl: 1200,   // 超大螢幕
    xxl: 1400   // 超超大螢幕
  }

  // ==================== 計算屬性 ====================
  
  /**
   * 主要面板寬度計算屬性
   * 考慮左右面板寬度，確保最小寬度
   */
  const mainPanelWidth = computed(() => {
    const availableWidth = windowWidth.value - leftPanelWidth.value - rightPanelWidth.value
    return Math.max(200, availableWidth) // 確保最小寬度
  })

  /**
   * 地圖高度計算屬性
   * 考慮底部面板和頂部導航欄高度
   */
  const mapHeight = computed(() => {
    const availableHeight = windowHeight.value - bottomPanelHeight.value - 60 // 60px for header
    return Math.max(300, availableHeight) // 確保最小高度
  })

  /**
   * 當前 Bootstrap 斷點計算屬性
   * 根據視窗寬度返回對應的斷點
   */
  const currentBreakpoint = computed(() => {
    const width = windowWidth.value
    if (width >= breakpoints.xxl) return 'xxl'
    if (width >= breakpoints.xl) return 'xl'
    if (width >= breakpoints.lg) return 'lg'
    if (width >= breakpoints.md) return 'md'
    if (width >= breakpoints.sm) return 'sm'
    return 'xs'
  })

  /**
   * 是否為移動裝置計算屬性
   * 根據當前斷點判斷
   */
  const isMobile = computed(() => {
    return currentBreakpoint.value === 'xs' || currentBreakpoint.value === 'sm'
  })

  /**
   * 響應式面板設定計算屬性
   * 根據當前斷點返回對應的面板設定
   */
  const responsivePanelSizes = computed(() => {
    const bp = currentBreakpoint.value
    
    if (bp === 'xs' || bp === 'sm') {
      // 小螢幕：面板可收合，滿版顯示
      return {
        leftPanel: 0,
        rightPanel: 0,
        bottomPanel: 200,
        collapsible: true
      }
    } else if (bp === 'md') {
      // 中等螢幕：縮小面板
      return {
        leftPanel: 250,
        rightPanel: 250,
        bottomPanel: 200,
        collapsible: true
      }
    } else {
      // 大螢幕：正常面板大小
      return {
        leftPanel: 300,
        rightPanel: 300,
        bottomPanel: 250,
        collapsible: false
      }
    }
  })

  // ==================== 方法 ====================

  /**
   * 更新視窗尺寸並調整面板
   * 響應視窗大小變化
   */
  const updateWindowSize = () => {
    windowWidth.value = window.innerWidth
    windowHeight.value = window.innerHeight
    
    // 根據新的視窗大小調整面板
    adjustPanelsForBreakpoint()
  }

  /**
   * 根據斷點調整面板大小
   * 確保面板大小符合當前螢幕尺寸
   */
  const adjustPanelsForBreakpoint = () => {
    const responsive = responsivePanelSizes.value
    
    if (responsive.collapsible) {
      // 在小螢幕上收合面板
      leftPanelWidth.value = 0
      rightPanelWidth.value = 0
    } else {
      leftPanelWidth.value = responsive.leftPanel
      rightPanelWidth.value = responsive.rightPanel
    }
    
    bottomPanelHeight.value = responsive.bottomPanel
  }

  /**
   * 重置面板尺寸
   * 恢復到當前斷點下的預設尺寸
   */
  const resetPanelSizes = () => {
    const responsive = responsivePanelSizes.value
    leftPanelWidth.value = responsive.leftPanel
    rightPanelWidth.value = responsive.rightPanel
    bottomPanelHeight.value = responsive.bottomPanel
  }

  /**
   * 更新左側面板寬度
   * @param {number} width - 新的寬度值
   */
  const updateLeftPanelWidth = (width) => {
    const maxWidth = windowWidth.value - rightPanelWidth.value - 300 // 保留右側面板和最小主畫面寬度
    leftPanelWidth.value = Math.max(0, Math.min(maxWidth, width))
  }

  /**
   * 更新右側面板寬度
   * @param {number} width - 新的寬度值
   */
  const updateRightPanelWidth = (width) => {
    const maxWidth = windowWidth.value - leftPanelWidth.value - 300 // 保留左側面板和最小主畫面寬度
    rightPanelWidth.value = Math.max(0, Math.min(maxWidth, width))
  }

  /**
   * 更新底部面板高度
   * @param {number} height - 新的高度值
   */
  const updateBottomPanelHeight = (height) => {
    const maxHeight = windowHeight.value - 150 // 保留最小地圖高度
    bottomPanelHeight.value = Math.max(0, Math.min(maxHeight, height))
  }

  /**
   * 切換面板顯示/隱藏
   * @param {string} panelType - 面板類型（left/right/bottom）
   */
  const togglePanel = (panelType) => {
    switch (panelType) {
      case 'left':
        leftPanelWidth.value = leftPanelWidth.value > 0 ? 0 : responsivePanelSizes.value.leftPanel
        break
      case 'right':
        rightPanelWidth.value = rightPanelWidth.value > 0 ? 0 : responsivePanelSizes.value.rightPanel
        break
      case 'bottom':
        bottomPanelHeight.value = bottomPanelHeight.value > 0 ? 0 : responsivePanelSizes.value.bottomPanel
        break
    }
  }

  /**
   * 更新地圖相關狀態
   * @param {Object} newState - 新的地圖狀態
   */
  const updateMapState = (newState) => {
    if (newState.zoomLevel !== undefined) zoomLevel.value = newState.zoomLevel
    if (newState.currentCoords !== undefined) currentCoords.value = newState.currentCoords
  }

  /**
   * 更新圖層狀態
   * @param {string} layer - 圖層名稱
   * @param {boolean} visible - 是否顯示
   */
  const updateLayerState = (layer, visible) => {
    if (layer === 'layer1') showLayer1.value = visible
    if (layer === 'layer2') showLayer2.value = visible
  }

  /**
   * 設定地圖圖層
   * @param {string} layerType - 圖層類型
   * @param {Object} layer - 圖層對象
   */
  const setMapLayer = (layerType, layer) => {
    mapLayers.value[layerType] = layer
    console.log(`✅ 地圖圖層已設定: ${layerType}`)
  }

  /**
   * 移除地圖圖層
   * @param {string} layerType - 圖層類型
   */
  const removeMapLayer = (layerType) => {
    if (mapLayers.value[layerType]) {
      mapLayers.value[layerType] = null
      console.log(`✅ 地圖圖層已移除: ${layerType}`)
    }
  }

  /**
   * 更新統計數據
   * @param {Object} newStats - 新的統計數據
   */
  const updateStatistics = (newStats) => {
    if (newStats.totalCount !== undefined) totalCount.value = newStats.totalCount
    if (newStats.selectedCount !== undefined) selectedCount.value = newStats.selectedCount
  }

  /**
   * 更新圖表類型
   * @param {string} type - 圖表類型
   */
  const updateChartType = (type) => {
    chartType.value = type
  }

  /**
   * 轉換座標從 TWD97 到 WGS84
   * @param {number} x - TWD97 東座標
   * @param {number} y - TWD97 北座標
   * @returns {Array} [lng, lat] WGS84 經緯度座標
   */
  const transformTWD97ToWGS84Coords = (x, y) => {
    try {
      const [lng, lat] = transformTWD97ToWGS84(x, y)
      return [lng, lat]
    } catch (error) {
      console.error('❌ MapStore: 座標轉換失敗:', error)
      return null
    }
  }

  /**
   * 檢測並轉換 GeoJSON 座標系統
   * @param {Object} geojson - 輸入的 GeoJSON 數據
   * @returns {Object} 轉換後的 GeoJSON 數據
   */
  const detectAndTransformCoordinates = (geojson) => {
    try {
      // 檢查是否為 TWD97 座標系統
      const isTWD97 = checkIfTWD97(geojson)
      
      if (isTWD97) {
        // 轉換為 WGS84
        const transformed = transformGeoJSONCoordinates(geojson)
        coordinateSystem.value = 'WGS84'
        transformedData.value = transformed
        return transformed
      }
      
      // 已經是 WGS84，直接返回
      coordinateSystem.value = 'WGS84'
      transformedData.value = geojson
      return geojson
    } catch (error) {
      console.error('❌ MapStore: GeoJSON 座標轉換失敗:', error)
      return geojson
    }
  }

  /**
   * 檢查 GeoJSON 是否使用 TWD97 座標系統
   * @param {Object} geojson - 輸入的 GeoJSON 數據
   * @returns {boolean} 是否為 TWD97 座標系統
   */
  const checkIfTWD97 = (geojson) => {
    try {
      // 檢查第一個座標點
      const firstCoord = geojson.features[0].geometry.coordinates[0]
      return firstCoord[0] > 120 && firstCoord[0] < 122 && firstCoord[1] > 22 && firstCoord[1] < 25
    } catch (error) {
      console.error('❌ MapStore: 座標系統檢查失敗:', error)
      return false
    }
  }

  /**
   * 更新座標系統
   * @param {string} system - 座標系統（'WGS84' 或 'TWD97'）
   */
  const updateCoordinateSystem = (system) => {
    coordinateSystem.value = system
  }

  /**
   * 獲取當前座標系統
   * @returns {string} 當前座標系統
   */
  const getCurrentCoordinateSystem = () => {
    return coordinateSystem.value
  }

  /**
   * 獲取轉換後的數據
   * @returns {Object} 轉換後的 GeoJSON 數據
   */
  const getTransformedData = () => {
    return transformedData.value
  }

  /**
   * 清除所有地圖相關狀態
   */
  const clearMapState = () => {
    // 重置面板尺寸
    resetPanelSizes()
    
    // 清除圖層狀態
    showLayer1.value = true
    showLayer2.value = false
    selectedFilter.value = ''
    timeRange.value = 50
    
    // 重置地圖狀態
    zoomLevel.value = 10
    currentCoords.value = { lat: 25.0330, lng: 121.5654 }
    
    // 清除統計數據
    totalCount.value = 0
    selectedCount.value = 0
    
    // 清除圖層
    Object.keys(mapLayers.value).forEach(key => {
      mapLayers.value[key] = null
    })
    
    // 重置座標系統
    coordinateSystem.value = 'WGS84'
    transformedData.value = null
  }

  // 返回所有狀態和方法
  return {
    // 狀態
    leftPanelWidth,
    rightPanelWidth,
    bottomPanelHeight,
    windowWidth,
    windowHeight,
    showLayer1,
    showLayer2,
    selectedFilter,
    timeRange,
    zoomLevel,
    currentCoords,
    totalCount,
    selectedCount,
    chartType,
    mapLayers,
    coordinateSystem,
    transformedData,
    
    // 計算屬性
    mainPanelWidth,
    mapHeight,
    currentBreakpoint,
    isMobile,
    responsivePanelSizes,
    
    // 方法
    updateWindowSize,
    adjustPanelsForBreakpoint,
    resetPanelSizes,
    updateLeftPanelWidth,
    updateRightPanelWidth,
    updateBottomPanelHeight,
    togglePanel,
    updateMapState,
    updateLayerState,
    setMapLayer,
    removeMapLayer,
    updateStatistics,
    updateChartType,
    transformTWD97ToWGS84Coords,
    detectAndTransformCoordinates,
    checkIfTWD97,
    updateCoordinateSystem,
    getCurrentCoordinateSystem,
    getTransformedData,
    clearMapState
  }
}) 