/**
 * 📦 dataStore.js - 數據管理 Store
 * 
 * 功能說明：
 * 1. 📊 管理原始數據和處理後的數據
 * 2. 🎨 管理視覺化設定和主題
 * 3. 📈 管理分析參數和結果
 * 4. 🔄 提供數據操作方法
 */

// 🧩 引入必要的依賴
import { defineStore } from 'pinia'                    // Pinia 狀態管理
import { ref, computed, reactive, watch } from 'vue'          // Vue 響應式 API
import { defaultColorConfig, ColorSchemeUtils } from '@/utils/pythonColorSchemes.js'  // 顏色方案工具
import { calculateDataSummary } from '../utils/dataProcessor'

// 📦 定義數據管理 store
export const useDataStore = defineStore('data', () => {
  // ==================== 原始資料狀態 ====================
  const rawData = ref({
    geojson: null,        // 原始GeoJSON資料 - 存儲地理空間數據
    csvData: [],          // CSV資料 - 存儲表格數據
    excelData: [],        // Excel資料 - 存儲表格數據
    spatialData: [],      // 空間分析資料 - 存儲空間分析相關數據
    metadata: {}          // 資料元資訊 - 存儲數據的相關描述和屬性
  })

  // ==================== 處理後資料狀態 ====================
  const processedData = ref({
    transformedGeojson: null,    // 座標轉換後的GeoJSON - 用於地圖顯示
    spatialAnalysisResults: {},  // 空間分析結果 - 存儲各種空間分析方法的結果
    statisticsResults: {},       // 統計分析結果 - 存儲描述性統計結果
    clusteringResults: {},       // 聚類分析結果 - 存儲聚類分析結果
    heatmapData: [],            // 熱力圖資料 - 存儲熱力圖相關數據
    boundaryData: {},            // 邊界資料 - 存儲地理邊界數據
    loadedAndMergedGeoJSON: null, // 從 loader 載入並合併的 GeoJSON - 整合後的空間數據
    loadedAndMergedTableData: [],  // 從 loader 載入並合併的表格數據 - 整合後的表格數據
    dataSummary: {
      maxCount: 0,
      minCount: 0,
      averageCount: 0,
      totalCount: 0,
      totalDataPoints: 0,
      dataRegionsCount: 0
    }
  })

  // ==================== 視覺化設定 ====================
  const visualizationSettings = reactive({
    colors: {
      levels: defaultColorConfig.levels,  // 顏色等級設定
      pythonSchemes: {
        default: defaultColorConfig.default,    // 預設顏色方案
        spatial: defaultColorConfig.spatial,    // 空間分析顏色方案
        heatmap: defaultColorConfig.heatmap,    // 熱力圖顏色方案
        categorical: defaultColorConfig.categorical  // 分類數據顏色方案
      },
      currentScheme: {
        name: 'viridis',           // 當前使用的顏色方案名稱
        library: 'matplotlib',     // 顏色方案庫
        colors: defaultColorConfig.default,  // 顏色值
        type: 'sequential'         // 顏色方案類型
      },
      100: '#dbeafe',  // 淺藍色
      200: '#93c5fd',  // 中藍色
      400: '#3b82f6',  // 深藍色
      800: '#1e40af'   // 最深藍色
    },
    charts: {
      defaultType: 'bar',          // 預設圖表類型
      animationEnabled: true,      // 是否啟用動畫
      showLegend: true,            // 是否顯示圖例
      colorScheme: {
        name: 'tab10',             // 圖表顏色方案名稱
        library: 'matplotlib',     // 顏色方案庫
        colors: ColorSchemeUtils.getColorScheme('tab10', 'matplotlib')  // 顏色值
      }
    },
    maps: {
      defaultStyle: 'openstreetmap',  // 預設地圖樣式
      showControls: true,             // 是否顯示地圖控制項
      enableClustering: false,        // 是否啟用點聚合
      colorMapping: {
        scheme: 'spectral',           // 顏色映射方案
        library: 'matplotlib',        // 顏色方案庫
        colors: ColorSchemeUtils.getColorScheme('spectral', 'matplotlib'),  // 顏色值
        interpolation: 'linear'       // 顏色插值方法
      }
    },
    themes: {
      current: 'default',  // 當前使用的主題
      available: {
        default: {
          name: '預設主題',
          description: '使用 Viridis 色票的科學視覺化主題',
          colors: ColorSchemeUtils.generateFourLevelColors(
            ColorSchemeUtils.getColorScheme('viridis', 'matplotlib')
          )
        },
        scientific: {
          name: '科學期刊',
          description: '適合科學期刊發表的專業色票',
          colors: ColorSchemeUtils.generateFourLevelColors(
            ColorSchemeUtils.getColorScheme('plasma', 'matplotlib')
          )
        },
        colorblind: {
          name: '色盲友好',
          description: '適合色盲使用者的友好色票',
          colors: ColorSchemeUtils.generateFourLevelColors(
            ColorSchemeUtils.getColorScheme('colorblind', 'seaborn')
          )
        },
        presentation: {
          name: '簡報展示',
          description: '適合簡報和展示的高對比色票',
          colors: ColorSchemeUtils.generateFourLevelColors(
            ColorSchemeUtils.getColorScheme('bright', 'seaborn')
          )
        }
      }
    }
  })

  // ==================== 分析參數 ====================
  const analysisParameters = ref({
    spatialAnalysis: {
      kValue: 5,           // K最近鄰的K值 - 用於空間自相關分析
      weightType: 'inverse_distance', // 權重類型 - 用於空間權重計算
      threshold: 0.5,      // 聚集檢測閾值 - 用於判斷空間聚集
      bufferRadius: 1000   // 緩衝區半徑（公尺）- 用於空間分析
    },
    clustering: {
      method: 'kmeans',    // 聚類方法 - 可選 kmeans 或 dbscan
      numClusters: 5,      // 聚類數量 - 用於 kmeans
      eps: 0.5,           // DBSCAN參數 - 用於 dbscan
      minPts: 5           // DBSCAN最小點數 - 用於 dbscan
    },
    heatmap: {
      radius: 500,        // 影響半徑（公尺）- 用於熱力圖
      gridSize: 50,       // 網格大小 - 用於熱力圖
      intensity: 1.0      // 強度 - 用於熱力圖
    }
  })

  // ==================== 計算屬性 ====================
  
  /**
   * 存儲從 loadAllDataUtil 載入的數據
   * @param {Object} data - 包含 mergedGeoJSON 和 tableData 的數據對象
   */
  const storeLoadedData = (data) => {
    if (data) {
      // 更新處理後的數據
      processedData.value.loadedAndMergedGeoJSON = data.mergedGeoJSON;
      processedData.value.loadedAndMergedTableData = Array.isArray(data.tableData) ? data.tableData : [];
      
      // 更新原始數據
      if (processedData.value.loadedAndMergedGeoJSON) {
        rawData.value.geojson = processedData.value.loadedAndMergedGeoJSON;
        rawData.value.metadata.geojson = { 
          ...(rawData.value.metadata.geojson || {}),
          timestamp: new Date().toISOString(),
          source: 'loadAllDataUtil',
          description: 'Main dataset loaded via Tainan data utility'
        };
      }

      console.log('✅ 主要數據已存入 Pinia Store (processedData & rawData.geojson 更新):', {
        geojsonFeatures: data.mergedGeoJSON?.features?.length,
        tableDataRows: data.tableData?.length
      });

      // 計算摘要
      processedData.value.dataSummary = calculateDataSummary(data.tableData);
    } else {
      console.warn('Pinia storeLoadedData: 接收到空的 data');
    }
  };
  
  /**
   * 數據統計摘要 - 計算屬性
   * 提供數據的基本統計信息
   */
  const dataSummary = computed(() => {
    const summary = {
      totalFeatures: 0,      // 總特徵數
      totalPoints: 0,        // 總點數
      dataTypes: [],         // 數據類型列表
      coordinateSystem: 'unknown',  // 座標系統
      boundingBox: null      // 邊界框
    }

    // 處理 GeoJSON 數據
    if (rawData.value.geojson) {
      summary.totalFeatures = rawData.value.geojson.features?.length || 0
      summary.dataTypes.push('GeoJSON')
      
      // 檢測座標系統
      if (rawData.value.geojson.features?.length > 0) {
        const firstCoord = rawData.value.geojson.features[0].geometry?.coordinates
        if (firstCoord && Array.isArray(firstCoord)) {
          const coord = Array.isArray(firstCoord[0]) ? firstCoord[0][0] : firstCoord[0]
          summary.coordinateSystem = coord > 180 ? 'TWD97' : 'WGS84'
        }
      }
    }

    // 處理 CSV 數據
    if (rawData.value.csvData.length > 0) {
      summary.totalPoints += rawData.value.csvData.length
      summary.dataTypes.push('CSV')
    }

    // 處理 Excel 數據
    if (rawData.value.excelData.length > 0) {
      summary.totalPoints += rawData.value.excelData.length
      summary.dataTypes.push('Excel')
    }

    return summary
  })

  /**
   * 可用的分析方法 - 計算屬性
   * 根據當前數據類型返回可用的分析方法
   */
  const availableAnalysisMethods = computed(() => {
    const methods = []
    
    // 如果有空間數據，添加空間分析方法
    if (rawData.value.geojson || rawData.value.spatialData.length > 0) {
      methods.push(
        'spatial_autocorrelation',  // 空間自相關分析
        'cluster_detection',        // 聚集檢測
        'nearest_neighbor',         // 最近鄰分析
        'spatial_lag',             // 空間滯後分析
        'hotspot_analysis'         // 熱點分析
      )
    }

    // 如果有表格數據，添加統計分析方法
    if (rawData.value.csvData.length > 0 || rawData.value.excelData.length > 0) {
      methods.push(
        'descriptive_statistics',   // 描述性統計
        'correlation_analysis',     // 相關分析
        'clustering'               // 聚類分析
      )
    }

    return methods
  })

  // ==================== 資料操作方法 ====================

  /**
   * 設定原始資料
   * @param {string} dataType - 數據類型
   * @param {any} data - 數據內容
   * @param {Object} metadata - 元數據
   */
  const setRawData = (dataType, data, metadata = {}) => {
    rawData.value[dataType] = data
    rawData.value.metadata[dataType] = {
      ...metadata,
      timestamp: new Date().toISOString(),
      size: JSON.stringify(data).length
    }
    
    console.log(`✅ 資料已存入 Store: ${dataType}`, {
      dataSize: data?.length || Object.keys(data || {}).length,
      metadata: rawData.value.metadata[dataType]
    })
  }

  /**
   * 設定處理後資料
   * @param {string} dataType - 數據類型
   * @param {any} data - 數據內容
   * @param {Object} analysisInfo - 分析信息
   */
  const setProcessedData = (dataType, data, analysisInfo = {}) => {
    processedData.value[dataType] = data
    processedData.value[`${dataType}_info`] = {
      ...analysisInfo,
      timestamp: new Date().toISOString(),
      parameters: { ...analysisParameters.value }
    }

    console.log(`✅ 處理後資料已存入 Store: ${dataType}`, {
      resultSize: data?.length || Object.keys(data || {}).length,
      analysisInfo
    })
  }

  /**
   * 更新視覺化設定
   * @param {string} settingType - 設定類型（colors/charts/maps/themes）
   * @param {Object} newSettings - 新的設定值
   */
  const updateVisualizationSettings = (settingType, newSettings) => {
    if (visualizationSettings[settingType]) {
      Object.assign(visualizationSettings[settingType], newSettings)
      console.log(`✅ 視覺化設定已更新: ${settingType}`, newSettings)
    }
  }

  /**
   * 更新分析參數
   * @param {string} paramType - 參數類型（spatialAnalysis/clustering/heatmap）
   * @param {Object} newParams - 新的參數值
   */
  const updateAnalysisParameters = (paramType, newParams) => {
    if (analysisParameters.value[paramType]) {
      Object.assign(analysisParameters.value[paramType], newParams)
      console.log(`✅ 分析參數已更新: ${paramType}`, newParams)
    }
  }

  /**
   * 清除指定類型的數據
   * @param {string} dataType - 要清除的數據類型
   */
  const clearData = (dataType) => {
    if (rawData.value[dataType]) {
      rawData.value[dataType] = null
      rawData.value.metadata[dataType] = {}
      console.log(`✅ 數據已清除: ${dataType}`)
    }
  }

  /**
   * 清除所有數據
   */
  const clearAllData = () => {
    Object.keys(rawData.value).forEach(key => {
      if (Array.isArray(rawData.value[key])) {
        rawData.value[key] = []
      } else if (typeof rawData.value[key] === 'object') {
        rawData.value[key] = {}
      } else {
        rawData.value[key] = null
      }
    })
    console.log('✅ 所有數據已清除')
  }

  /**
   * 導出數據為 JSON 格式
   * @returns {string} JSON 字符串
   */
  const exportDataAsJSON = () => {
    const exportData = {
      rawData: rawData.value,
      processedData: processedData.value,
      visualizationSettings: visualizationSettings,
      analysisParameters: analysisParameters.value
    }
    return JSON.stringify(exportData, null, 2)
  }

  /**
   * 從 JSON 導入數據
   * @param {Object} jsonData - JSON 數據對象
   */
  const importDataFromJSON = (jsonData) => {
    try {
      if (jsonData.rawData) Object.assign(rawData.value, jsonData.rawData)
      if (jsonData.processedData) Object.assign(processedData.value, jsonData.processedData)
      if (jsonData.visualizationSettings) Object.assign(visualizationSettings, jsonData.visualizationSettings)
      if (jsonData.analysisParameters) Object.assign(analysisParameters.value, jsonData.analysisParameters)
      console.log('✅ 數據已從 JSON 導入')
    } catch (error) {
      console.error('❌ 導入數據時發生錯誤:', error)
    }
  }

  /**
   * 獲取指定類型的數據
   * @param {string} dataType - 數據類型
   * @param {boolean} processed - 是否獲取處理後的數據
   * @returns {any} 請求的數據
   */
  const getData = (dataType, processed = false) => {
    const data = processed ? processedData.value[dataType] : rawData.value[dataType]
    return data
  }

  /**
   * 檢查是否存在指定類型的數據
   * @param {string} dataType - 數據類型
   * @param {boolean} processed - 是否檢查處理後的數據
   * @returns {boolean} 是否存在數據
   */
  const hasData = (dataType, processed = false) => {
    const data = processed ? processedData.value[dataType] : rawData.value[dataType]
    return data !== null && data !== undefined && 
           (Array.isArray(data) ? data.length > 0 : Object.keys(data).length > 0)
  }

  /**
   * 更新顏色方案
   * @param {string} scheme - 顏色方案名稱
   * @param {string} library - 顏色方案庫
   * @param {string} type - 顏色方案類型
   */
  const updateColorScheme = (scheme, library = 'matplotlib', type = 'sequential') => {
    const colors = ColorSchemeUtils.getColorScheme(scheme, library)
    if (colors) {
      visualizationSettings.colors.currentScheme = {
        name: scheme,
        library: library,
        colors: colors,
        type: type
      }
      console.log(`✅ 顏色方案已更新: ${scheme} (${library})`)
    }
  }

  /**
   * 獲取推薦的顏色方案
   * @param {string} dataType - 數據類型
   * @returns {Object} 推薦的顏色方案
   */
  const getRecommendedColorSchemes = (dataType) => {
    // 根據數據類型返回推薦的顏色方案
    return visualizationSettings.colors.pythonSchemes[dataType] || 
           visualizationSettings.colors.pythonSchemes.default
  }

  /**
   * 應用主題
   * @param {string} themeName - 主題名稱
   */
  const applyTheme = (themeName) => {
    const theme = visualizationSettings.themes.available[themeName]
    if (theme) {
      visualizationSettings.themes.current = themeName
      visualizationSettings.colors.levels = theme.colors
      console.log(`✅ 主題已應用: ${themeName}`)
    }
  }

  /**
   * 觸發視覺化更新
   */
  const triggerVisualizationUpdate = () => {
    // 觸發視覺化更新的事件或操作
    console.log('🔄 視覺化更新已觸發')
  }

  /**
   * 獲取所有可用的顏色方案
   * @returns {Object} 顏色方案對象
   */
  const getAllAvailableColorSchemes = () => {
    return {
      matplotlib: ColorSchemeUtils.getMatplotlibSchemes(),
      seaborn: ColorSchemeUtils.getSeabornSchemes(),
      custom: visualizationSettings.colors.pythonSchemes
    }
  }

  /**
   * 將值映射到顏色
   * @param {number} value - 要映射的值
   * @param {number} min - 最小值
   * @param {number} max - 最大值
   * @param {string} scheme - 顏色方案
   * @param {string} library - 顏色方案庫
   * @returns {string} 映射後的顏色
   */
  const mapValueToColor = (value, min, max, scheme = null, library = null) => {
    const currentScheme = scheme ? 
      ColorSchemeUtils.getColorScheme(scheme, library) : 
      visualizationSettings.colors.currentScheme.colors
    return ColorSchemeUtils.mapValueToColor(value, min, max, currentScheme)
  }

  /**
   * 獲取最新數據
   * @returns {Promise} 數據獲取 Promise
   */
  const fetchLatestData = async () => {
    try {
      // 實現數據獲取邏輯
      console.log('🔄 正在獲取最新數據...')
    } catch (error) {
      console.error('❌ 獲取數據時發生錯誤:', error)
    }
  }

  // ==================== 自動監控 Table Data 變動，自動更新 dataSummary ====================
  watch(
    () => processedData.value.loadedAndMergedTableData,
    (newTableData) => {
      processedData.value.dataSummary = calculateDataSummary(newTableData)
    },
    { deep: true }
  )

  const mergedTableData = computed(() => processedData.value.loadedAndMergedTableData)

  // 返回所有方法和狀態
  return {
    // 狀態
    rawData,
    processedData,
    visualizationSettings,
    analysisParameters,
    
    // 計算屬性
    dataSummary,
    availableAnalysisMethods,
    
    // 方法
    storeLoadedData,
    setRawData,
    setProcessedData,
    updateVisualizationSettings,
    updateAnalysisParameters,
    clearData,
    clearAllData,
    exportDataAsJSON,
    importDataFromJSON,
    getData,
    hasData,
    updateColorScheme,
    getRecommendedColorSchemes,
    applyTheme,
    triggerVisualizationUpdate,
    getAllAvailableColorSchemes,
    mapValueToColor,
    fetchLatestData,
    mergedTableData
  }
}) 